sql:
SELECT location, MAX(capacity_percentage) AS max_capacity
FROM car_parks
GROUP BY location;

SELECT carpark_id, SUM(lots_available) AS Total_Lots_Available
FROM parking_availability
GROUP BY carpark_id;

SELECT total_lots 
FROM car_parks 
WHERE carpark_id = 1234;

SELECT AVG(CAST(lots_available AS REAL) / total_lots) * 100 AS average_capacity_percentage
FROM parking_availability
INNER JOIN car_parks ON parking_availability.carpark_id = car_parks.carpark_id;

external_knowledge:
- 'streets' metaphorically refers to 'car park numbers';
- 'common wanderers' refers to 'regular users';
- 'timings of their strolls' refer to 'start time' and 'end time' of the reservations;
- 'traveler names' refer to 'user names';
- 'nature of their journey' refers to the 'status' of the reservation;
- 'whether they are just passing through or have settled in' refers to 'reservation type';
- 'payment tales' refers to 'payment status';
- 'reasons for turning back' refers to 'cancellation reason';
- 'hour at which they first embarked on their journey' refers to 'start time' sorted in ascending order.

sql:
SELECT location, COUNT(carpark_id) as car_park_count
FROM car_parks
GROUP BY location;

SELECT 
    (SELECT COUNT(*) FROM users WHERE user_id IN (SELECT DISTINCT user_id FROM reservations)) AS users_with_reservations,
    (SELECT COUNT(*) FROM users WHERE user_id NOT IN (SELECT DISTINCT user_id FROM reservations)) AS users_without_reservations;

SELECT review_text, rating
FROM car_park_reviews
WHERE carpark_id = 'Your_Car_Park_ID';

SELECT user_name
FROM users
WHERE user_id IN (SELECT user_id FROM reservations);

external_knowledge:
- "quite active" implies users who have a high number of reservations;
- "recent past" is defined as the last three months from the current date;
- "booked more than three unique spots" refers to the number of distinct car parks reserved by users.

- "recently checked over" refers to car parks that have had their safety and maintenance inspected within the last 30 days; 
- "certain area" refers to the specific location mentioned in the SQL query, specified for the car park to be located there; 
- "current availability of parking spots" means the most up-to-date count of lots that are available for parking.
